          # helper to join multiple objects nicely
          def join_objs(objs: list[str]) -> str:
              if not objs:
                  return ""
              if len(objs) == 1:
                  return objs[0]
              return ", ".join(objs[:-1]) + " and " + objs[-1]

          # generate phrase for each predicate using more natural wording
